export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export type CSVRow = Record<string, unknown>;

export class CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];

  constructor(rows: CSVRow[], headers: string[], errors: CSVError[]) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate: (row: CSVRow) => boolean): CSVRow[] {
    return this.rows.filter(predicate);
  }

  sum(column: string): number {
    let total = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === "number" && !Number.isNaN(value)) {
        total += value;
      }
    }
    return total;
  }

  average(column: string): number {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === "number" && !Number.isNaN(value)) {
        total += value;
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<unknown, CSVRow[]> {
    const groups = new Map<unknown, CSVRow[]>();
    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }
    return groups;
  }
}

function coerceValue(raw: string | undefined): unknown {
  if (raw === undefined) {
    return null;
  }
  if (raw === "") {
    return null;
  }
  const lower = raw.toLowerCase();
  if (lower === "null") {
    return null;
  }
  if (lower === "true") {
    return true;
  }
  if (lower === "false") {
    return false;
  }
  if (/^-?\d+(?:\.\d+)?$/.test(raw)) {
    return Number(raw);
  }
  return raw;
}

function parseRawRows(input: string, delimiter: string, quoteChar: string, lineSeparator: string): { rows: string[][]; errors: CSVError[] } {
  const rows: string[][] = [];
  const errors: CSVError[] = [];
  if (input.length === 0) {
    return { rows, errors };
  }

  let currentField = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  let i = 0;

  const delimiterLength = delimiter.length;
  const lineSeparatorLength = lineSeparator.length;

  const isLineSeparatorAt = (index: number): boolean => {
    if (lineSeparatorLength === 0) {
      return false;
    }
    if (input.startsWith(lineSeparator, index)) {
      return true;
    }
    if (lineSeparator === "\n" && input[index] === "\r" && input[index + 1] === "\n") {
      return true;
    }
    return false;
  };

  const advanceLineSeparator = (index: number): number => {
    if (lineSeparator === "\n" && input[index] === "\r" && input[index + 1] === "\n") {
      return 2;
    }
    return lineSeparatorLength;
  };

  while (i < input.length) {
    const char = input[i];

    if (inQuotes) {
      if (char === quoteChar) {
        const nextChar = input[i + 1];
        if (nextChar === quoteChar) {
          currentField += quoteChar;
          i += 2;
          continue;
        }
        inQuotes = false;
        i += 1;
        continue;
      }
      currentField += char;
      i += 1;
      continue;
    }

    if (char === quoteChar) {
      inQuotes = true;
      i += 1;
      continue;
    }

    if (delimiterLength > 0 && input.startsWith(delimiter, i)) {
      currentRow.push(currentField);
      currentField = "";
      i += delimiterLength;
      continue;
    }

    if (isLineSeparatorAt(i)) {
      currentRow.push(currentField);
      currentField = "";
      rows.push(currentRow);
      currentRow = [];
      i += advanceLineSeparator(i);
      continue;
    }

    currentField += char;
    i += 1;
  }

  if (inQuotes) {
    const rowNumber = rows.length + 1;
    errors.push({ row: rowNumber, message: "Unclosed quote in field" });
  }

  const hasTrailingData = currentRow.length > 0 || currentField.length > 0 || input.endsWith(delimiter);
  if (hasTrailingData) {
    currentRow.push(currentField);
    rows.push(currentRow);
  }

  return { rows, errors };
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quoteChar = options?.quoteChar ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const { rows: rawRows, errors: parseErrors } = parseRawRows(input, delimiter, quoteChar, lineSeparator);

  if (rawRows.length === 0) {
    return new CSVResult([], [], parseErrors);
  }

  const headers = rawRows[0].map((header) => header);
  const rows: CSVRow[] = [];
  const errors: CSVError[] = [...parseErrors];

  for (let i = 1; i < rawRows.length; i += 1) {
    const rawRow = rawRows[i];
    if (rawRow.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Expected ${headers.length} fields but got ${rawRow.length}`,
      });
    }
    const rowObject: CSVRow = {};
    for (let h = 0; h < headers.length; h += 1) {
      const header = headers[h];
      const value = rawRow[h];
      rowObject[header] = value === undefined ? null : coerceValue(value);
    }
    rows.push(rowObject);
  }

  return new CSVResult(rows, headers, errors);
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual<T>(actual: T, expected: T, message: string) {
  if (actual !== expected) {
    throw new Error(`${message}. Expected ${expected} but got ${actual}`);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string) {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}. Expected ${expectedJson} but got ${actualJson}`);
  }
}

(function testBasicParsing() {
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertDeepEqual(result.headers, ["name", "age"], "Headers should match");
  assertEqual(result.rows.length, 2, "Should parse two rows");
  assertEqual(result.rows[0].name as string, "Alice", "First name should be Alice");
  assertEqual(result.rows[1].age as number, 25, "Second age should be 25");
})();

(function testQuotedFieldsWithCommas() {
  const input = "name,notes\nAlice,\"hello, world\"\nBob,\"a,b,c\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].notes as string, "hello, world", "Quoted field should keep comma");
  assertEqual(result.rows[1].notes as string, "a,b,c", "Quoted field should keep commas");
})();

(function testEscapedQuotes() {
  const input = "name,quote\nAlice,\"He said \"\"Hi\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote as string, "He said \"Hi\"", "Escaped quotes should be parsed");
})();

(function testCustomDelimiters() {
  const input = "col1;col2|1;'x;y'|2;3";
  const result = parseCSV(input, { delimiter: ";", quoteChar: "'", lineSeparator: "|" });
  assertEqual(result.rows.length, 2, "Custom delimiters should parse rows");
  assertEqual(result.rows[0].col2 as string, "x;y", "Custom quote char should work");
})();

(function testTypeCoercion() {
  const input = "a,b,c,d,e,f,g,h\n1,2.5,true,FALSE,null,NULL,,text";
  const result = parseCSV(input);
  const row = result.rows[0];
  assertEqual(row.a as number, 1, "Integer should coerce to number");
  assertEqual(row.b as number, 2.5, "Float should coerce to number");
  assertEqual(row.c as boolean, true, "True should coerce to boolean");
  assertEqual(row.d as boolean, false, "False should coerce to boolean");
  assertEqual(row.e as null, null, "null should coerce to null");
  assertEqual(row.f as null, null, "NULL should coerce to null");
  assertEqual(row.g as null, null, "Empty string should coerce to null");
  assertEqual(row.h as string, "text", "Non-matching string should remain string");
})();

(function testMalformedRowErrors() {
  const input = "a,b\n1\n2,3,4";
  const result = parseCSV(input);
  assertEqual(result.errors.length, 2, "Should collect two errors");
  assertEqual(result.errors[0].row, 2, "First error should be on row 2");
  assertEqual(result.errors[1].row, 3, "Second error should be on row 3");
  assertEqual(result.rows.length, 2, "Should still return parsed rows");
  assertEqual(result.rows[0].b as null, null, "Missing field should be null");
})();

(function testFilterFunctionality() {
  const input = "name,age\nAlice,30\nBob,25\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => (row.age as number) > 30);
  assertEqual(filtered.length, 1, "Filter should return matching rows");
  assertEqual(filtered[0].name as string, "Cara", "Filter should return correct row");
})();

(function testAggregationMethods() {
  const input = "group,value\nA,10\nA,20\nB,5";
  const result = parseCSV(input);
  assertEqual(result.count(), 3, "Count should return total rows");
  assertEqual(result.sum("value"), 35, "Sum should total numeric values");
  assertEqual(Math.round(result.average("value") * 100) / 100, 11.67, "Average should compute numeric mean");
  const groups = result.groupBy("group");
  assertEqual(groups.get("A")?.length ?? 0, 2, "GroupBy should group rows");
  assertEqual(groups.get("B")?.length ?? 0, 1, "GroupBy should group rows");
})();

(function testEdgeCases() {
  const emptyResult = parseCSV("");
  assertEqual(emptyResult.headers.length, 0, "Empty input should have no headers");
  assertEqual(emptyResult.rows.length, 0, "Empty input should have no rows");

  const singleColumn = parseCSV("a\n1\n2");
  assertDeepEqual(singleColumn.headers, ["a"], "Single column header should parse");
  assertEqual(singleColumn.rows.length, 2, "Single column rows should parse");

  const singleRow = parseCSV("a,b");
  assertEqual(singleRow.rows.length, 0, "Single row with only headers should have no data rows");

  const largeField = "x".repeat(10000);
  const largeInput = `col\n"${largeField}"`;
  const largeResult = parseCSV(largeInput);
  assertEqual(largeResult.rows[0].col as string, largeField, "Large field should parse correctly");
})();

console.log("All tests passed");

