  const lineSeparatorLength = lineSeparator.length;

  const isLineSeparatorAt = (index: number): boolean => {
    if (lineSeparatorLength === 0) {
      return false;
    }
    if (input.startsWith(lineSeparator, index)) {
      return true;
    }
    if (lineSeparator === "\n" && input[index] === "\r" && input[index + 1] === "\n") {
      return true;
    }
    return false;
  };

